glsl.vertex:
varying vec2 vUv;
void main(){
 vUv = uv;
 gl_Position = projectionMatrix * modelViewMatrix * vec4(position, 1.0);
}

glsl.fragment:
varying vec2 vUv;
uniform vec3 uBgColor;
uniform vec3 uPrimary;
uniform vec3 uSecondary;
uniform vec3 uAnchor;
uniform float uTime;
uniform float uSeed;
float hash(vec2 p){ return fract(sin(dot(p, vec2(127.1,311.7)) + uSeed * 17.0) * 43758.5453123); }
float noise(vec2 p){
 vec2 i = floor(p), f = fract(p);
 float a = hash(i), b = hash(i + vec2(1.0,0.0)), c = hash(i + vec2(0.0,1.0)), d = hash(i + vec2(1.0,1.0));
 vec2 u = f * f * (3.0 - 2.0 * f);
 return mix(a, b, u.x) + (c - a) * u.y * (1.0 - u.x) + (d - b) * u.x * u.y;
}
float fbm(vec2 p){
 float v = 0.0;
 float a = 0.5;
 for(int i=0;i<5;i++){
 v += a * noise(p);
 p *= 2.03;
 a *= 0.5;
 }
 return v;
}
void main(){
 vec2 uv = vUv;
 vec2 p = uv * vec2(1.0, 1.35);
 float n1 = fbm(p * 3.2 + vec2(0.0, uTime * 0.01));
 float n2 = fbm(p * 11.0 - vec2(0.0, uTime * 0.015));
 float stain = smoothstep(0.18, 0.86, n1);
 float scrape = smoothstep(0.56, 0.8, n2) * (1.0 - smoothstep(0.78, 0.96, n2));
 vec3 col = mix(uBgColor, uPrimary, stain * 0.72);
 col = mix(col, uSecondary, pow(n1, 2.1) * 0.24);
 col = mix(col, uAnchor, scrape * 0.08 * (1.0 - uv.y));
 float edgeDark = smoothstep(0.0, 0.16, uv.x) * smoothstep(1.0, 0.84, uv.x);
 col *= 0.82 + 0.18 * edgeDark;
 col *= 0.92 + 0.08 * sin((uv.y * 22.0 + n2 * 9.0));
 gl_FragColor = vec4(col, 1.0);
}

