glsl.fragment:
varying vec2 vUv;
uniform vec3 uPrimary;
uniform vec3 uSecondary;
uniform vec3 uGlow;
uniform float uTime;
uniform float uSeed;
float hash(vec2 p){ return fract(sin(dot(p, vec2(41.0,289.0)) + uSeed * 13.0) * 43758.5453); }
float noise(vec2 p){
 vec2 i = floor(p), f = fract(p);
 float a = hash(i), b = hash(i + vec2(1.0,0.0)), c = hash(i + vec2(0.0,1.0)), d = hash(i + vec2(1.0,1.0));
 vec2 u = f * f * (3.0 - 2.0 * f);
 return mix(a, b, u.x) + (c - a) * u.y * (1.0 - u.x) + (d - b) * u.x * u.y;
}
float ridge(vec2 p){
 float n = noise(p);
 return 1.0 - abs(n * 2.0 - 1.0);
}
float cleft(vec2 uv, float x0, float w, float seed){
 float y = uv.y;
 float j = ridge(vec2(y * 6.0, seed)) * 0.09 + noise(vec2(y * 15.0, seed + 4.0)) * 0.04;
 float center = x0 + (y - 0.5) * 0.08 + (j - 0.06);
 float halfW = w * (0.65 + 0.6 * (1.0 - y));
 float body = 1.0 - smoothstep(halfW, halfW + 0.018, abs(uv.x - center));
 float bites = smoothstep(0.55, 0.95, noise(vec2(y * 19.0, seed + 8.0))) * 0.32;
 return clamp(body - bites, 0.0, 1.0);
}
void main(){
 vec2 uv = vUv;
 float c1 = cleft(uv, 0.34, 0.09, 1.1);
 float c2 = cleft(uv, 0.53, 0.07, 2.3);
 float c3 = cleft(uv, 0.68, 0.05, 4.7);
 float mask = max(c1, max(c2, c3));
 float torn = ridge(vec2(uv.y * 24.0, uv.x * 3.0)) * 0.35;
 vec3 col = mix(uPrimary, uSecondary, uv.y * 0.7 + torn * 0.2);
 col = mix(col, uGlow, smoothstep(0.78, 1.0, torn) * 0.12);
 float alpha = mask * (0.92 - 0.18 * smoothstep(0.0, 0.12, uv.y));
 gl_FragColor = vec4(col, alpha);
}

