glsl.fragment:
varying vec2 vUv;
uniform vec3 uGlow;
uniform vec3 uSecondary;
uniform float uTime;
uniform float uSeed;
float hash(vec2 p){ return fract(sin(dot(p, vec2(91.7,12.4)) + uSeed * 9.0) * 43758.5453); }
float noise(vec2 p){
 vec2 i = floor(p), f = fract(p);
 float a = hash(i), b = hash(i + vec2(1.0,0.0)), c = hash(i + vec2(0.0,1.0)), d = hash(i + vec2(1.0,1.0));
 vec2 u = f * f * (3.0 - 2.0 * f);
 return mix(a, b, u.x) + (c - a) * u.y * (1.0 - u.x) + (d - b) * u.x * u.y;
}
void main(){
 vec2 uv = vUv;
 float center = 0.61 + (uv.y - 0.5) * 0.015 + (noise(vec2(uv.y * 20.0, 1.7)) - 0.5) * 0.018;
 float slit = exp(-abs(uv.x - center) * 210.0);
 float halo = exp(-abs(uv.x - center) * 55.0) * 0.22;
 float topBreak = smoothstep(0.18, 0.86, uv.y) * (0.88 + 0.12 * noise(vec2(uv.y * 12.0, 5.0)));
 vec3 col = mix(uSecondary, uGlow, slit);
 float alpha = clamp((slit + halo) * topBreak, 0.0, 1.0);
 gl_FragColor = vec4(col, alpha);
}

