uniform float uTime;
uniform float uSeed;
float hash(vec2 p){ return fract(sin(dot(p, vec2(17.0,157.0)) + uSeed * 5.0) * 43758.5453); }
float noise(vec2 p){
 vec2 i = floor(p), f = fract(p);
 float a = hash(i), b = hash(i + vec2(1.0,0.0)), c = hash(i + vec2(0.0,1.0)), d = hash(i + vec2(1.0,1.0));
 vec2 u = f * f * (3.0 - 2.0 * f);
 return mix(a, b, u.x) + (c - a) * u.y * (1.0 - u.x) + (d - b) * u.x * u.y;
}
void main(){
 vec2 uv = vUv;
 vec2 center = vec2(0.82, 0.56);
 vec2 d = uv - center;
 d.x *= 1.55;
 float r = length(d);
 float drag = smoothstep(0.34, 0.03, r);
 float asym = smoothstep(0.15, 0.95, uv.y) * smoothstep(1.0, 0.42, uv.x);
 float scrape = smoothstep(0.62, 0.88, noise(uv * 18.0 + vec2(0.0, 4.0))) * 0.4;
 vec3 col = mix(uBgColor * 0.7, uAnchor * 0.55, drag * 0.22 + scrape * 0.08);
 float alpha = (drag * 0.45 + scrape * 0.12) * asym;
 gl_FragColor = vec4(col, alpha);
}
